    a := CheckPostgresPing(t.Expect.Postgres)
    assertions = append(assertions, a)
    if !a.Passed {
        allPassed = false
    }
}
if t.Expect.MySQL != nil {
    a := CheckMySQLPing(t.Expect.MySQL)
    assertions = append(assertions, a)
    if !a.Passed {
        allPassed = false
    }
}
```

### 4. `CLAUDE.md` — update assertion table

In the assertion-types table, add TWO rows after `memcached_version`:
```
| postgres_ping | `{host?, port?}` | Postgres server SSLRequest handshake returns valid protocol byte |
| mysql_ping | `{host?, port?}` | MySQL server sends valid v10 handshake packet on connection |
```

## Tests to add

### `internal/runner/assertion_test.go`

Use the existing `startFakeRedis` / `startFakeMemcached` pattern (L926-972) — TCP listener that replies with canned bytes. Add two similar helpers:

```go
// startFakePostgres listens once, reads the SSLRequest, replies with a single byte.
func startFakePostgres(t *testing.T, reply byte) (string, int) {
    t.Helper()
    lis, err := net.Listen("tcp", "127.0.0.1:0")
    if err != nil { t.Fatal(err) }
    t.Cleanup(func() { lis.Close() })
    go func() {
        conn, err := lis.Accept()
        if err != nil { return }
        defer conn.Close()
        buf := make([]byte, 8)
        conn.Read(buf) //nolint:errcheck
        conn.Write([]byte{reply}) //nolint:errcheck
    }()
    host, portStr, _ := net.SplitHostPort(lis.Addr().String())
    port, _ := strconv.Atoi(portStr)
    return host, port
}

// startFakeMySQL listens once and immediately writes a handshake packet.
func startFakeMySQL(t *testing.T, protocolVersion byte) (string, int) {
    t.Helper()
    lis, err := net.Listen("tcp", "127.0.0.1:0")
    if err != nil { t.Fatal(err) }
    t.Cleanup(func() { lis.Close() })
    go func() {
        conn, err := lis.Accept()
        if err != nil { return }
        defer conn.Close()
        // 3-byte len, 1-byte seq, 1-byte protocol version + padding
        pkt := []byte{0x0a, 0x00, 0x00, 0x00, protocolVersion, 0x00, 0x00, 0x00, 0x00, 0x00}
        conn.Write(pkt) //nolint:errcheck
    }()
    host, portStr, _ := net.SplitHostPort(lis.Addr().String())
    port, _ := strconv.Atoi(portStr)
    return host, port
}
```

