```go
// CheckDockerContainerRunning passes if a container with the given name is running.
func CheckDockerContainerRunning(check *schema.DockerContainerCheck) AssertionResult {
    name := check.Name
    ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()

    // docker ps -q -f name=^NAME$  — outputs container ID if running, empty if not
    cmd := exec.CommandContext(ctx, "docker", "ps", "-q", "-f", "name=^"+name+"$")
    out, err := cmd.Output()
    if err != nil {
        if _, ok := err.(*exec.ExitError); ok {
            return AssertionResult{Type: "docker_container_running", Expected: name, Actual: "docker error: " + string(out), Passed: false}
        }
        return AssertionResult{Type: "docker_container_running", Expected: name, Actual: "exec error: " + err.Error(), Passed: false}
    }
    id := strings.TrimSpace(string(out))
    if id == "" {
        return AssertionResult{Type: "docker_container_running", Expected: name, Actual: "not running", Passed: false}
    }
    return AssertionResult{Type: "docker_container_running", Expected: name, Actual: "running (" + id + ")", Passed: true}
}

// CheckDockerImageExists passes if the named image is present in the local docker image store.
func CheckDockerImageExists(check *schema.DockerImageCheck) AssertionResult {
    image := check.Image
    ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()

    cmd := exec.CommandContext(ctx, "docker", "image", "inspect", image)
    // Discard stdout+stderr; we only care about exit code
    if err := cmd.Run(); err != nil {
        if exitErr, ok := err.(*exec.ExitError); ok {
            return AssertionResult{Type: "docker_image_exists", Expected: image, Actual: fmt.Sprintf("not found (exit %d)", exitErr.ExitCode()), Passed: false}
        }
        return AssertionResult{Type: "docker_image_exists", Expected: image, Actual: "exec error: " + err.Error(), Passed: false}
    }
    return AssertionResult{Type: "docker_image_exists", Expected: image, Actual: "present", Passed: true}
}
```

Imports already present in assertion.go: `context`, `exec`, `strings`, `time`, `fmt`, `schema`. No new imports needed.

