// isDockerAvailable returns true if the `docker` CLI is on PATH AND the daemon is reachable.
func isDockerAvailable() bool {
    if _, err := exec.LookPath("docker"); err != nil {
        return false
    }
    // Quick check: `docker info` returns 0 only when daemon is reachable.
    ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
