```go
func TestCheckDockerContainerRunning_RealContainer(t *testing.T) {
    if !isDockerAvailable() {
        t.Skip("docker daemon not available")
    }
    // Start ephemeral container
    name := "cosmo-smoke-test-" + fmt.Sprint(time.Now().UnixNano())
    cmd := exec.Command("docker", "run", "-d", "--rm", "--name", name, "alpine:3.20", "sleep", "30")
    if err := cmd.Run(); err != nil {
        t.Skipf("cannot start test container: %v", err)
    }
    t.Cleanup(func() {
        exec.Command("docker", "rm", "-f", name).Run()
    })
    // Give docker a moment
    time.Sleep(200 * time.Millisecond)

    r := CheckDockerContainerRunning(&schema.DockerContainerCheck{Name: name})
    if !r.Passed {
        t.Errorf("expected pass for running container, got fail: %+v", r)
    }
}
```

**`TestCheckDockerImageExists_RealImage`** — gated similarly, pulls `alpine:3.20`, then verifies the assertion finds it.

